-- Field: ModelSummary.ConfounderLatentOnlyCount
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_model_summary_confounder_latent_only_count(p_model_summary_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'confounder' AND calc_treatment_rankings_is_latent_only_flip(treatment_ranking_id) = TRUE))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_model_summary_collider_selection_count
-- Field: ModelSummary.ColliderSelectionCount
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_model_summary_collider_selection_count(p_model_summary_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_model_summary_collider_selection_manifest_count
-- Field: ModelSummary.ColliderSelectionManifestCount
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_model_summary_collider_selection_manifest_count(p_model_summary_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_model_summary_collider_selection_latent_only_count
-- Field: ModelSummary.ColliderSelectionLatentOnlyCount
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_model_summary_collider_selection_latent_only_count(p_model_summary_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'collider'))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT COUNT(*) FROM treatment_rankings WHERE calc_treatment_rankings_stratum_causal_role(treatment_ranking_id) = 'selection'))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_model_summary_discovery_witness_note
-- Field: ModelSummary.DiscoveryWitnessNote
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_model_summary_discovery_witness_note(p_model_summary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT('LatentTypeD=', calc_model_summary_latent_type_d_count(p_model_summary_id), '/', calc_model_summary_type_d_count(p_model_summary_id), '; SignFlipMaxPurity=', calc_model_summary_sign_flip_signal_purity_max(p_model_summary_id), '; stableD=', calc_model_summary_avg_pooled_gap_stable_d(p_model_summary_id), ' latentD=', calc_model_summary_avg_pooled_gap_latent_d(p_model_summary_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_stratum_variables_name
-- Field: StratumVariables.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_stratum_variables_name(p_stratum_variable_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(stratum_variable_id, '') FROM stratum_variables WHERE stratum_variable_id = p_stratum_variable_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_stratum_variables_is_confounder
-- Field: StratumVariables.IsConfounder
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_stratum_variables_is_confounder(p_stratum_variable_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((COALESCE((SELECT affects_treatment_assignment FROM stratum_variables WHERE stratum_variable_id = p_stratum_variable_id), FALSE) AND COALESCE((SELECT affects_outcome FROM stratum_variables WHERE stratum_variable_id = p_stratum_variable_id), FALSE) AND (SELECT NULLIF(causal_role, '') FROM stratum_variables WHERE stratum_variable_id = p_stratum_variable_id) = 'confounder'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_name
-- Field: TreatmentRankings.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_treatment_rankings_name(p_treatment_ranking_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(treatment_ranking_id, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_cases_a
-- Field: TreatmentRankings.TotalCasesA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_cases_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_successes_a
-- Field: TreatmentRankings.TotalSuccessesA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_successes_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_a
-- Field: TreatmentRankings.PooledRateA
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_total_cases_a(p_treatment_ranking_id))::NUMERIC = 0 THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_total_successes_a(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_total_successes_a(p_treatment_ranking_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_treatment_rankings_total_cases_a(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_total_cases_a(p_treatment_ranking_id))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_cases_b
-- Field: TreatmentRankings.TotalCasesB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_cases_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_successes_b
-- Field: TreatmentRankings.TotalSuccessesB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_successes_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_b
-- Field: TreatmentRankings.PooledRateB
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_total_cases_b(p_treatment_ranking_id))::NUMERIC = 0 THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_total_successes_b(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_total_successes_b(p_treatment_ranking_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_treatment_rankings_total_cases_b(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_total_cases_b(p_treatment_ranking_id))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_winner
-- Field: TreatmentRankings.PooledWinner
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_winner(p_treatment_ranking_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) IS NULL OR calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id) IS NULL) THEN ('')::text ELSE (CASE WHEN (ABS((COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::numeric ELSE NULL END, 0))))::NUMERIC < 0.0000001 THEN ('tie')::text ELSE (CASE WHEN calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) > calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id) THEN ((SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE ((SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_stratum_count
-- Field: TreatmentRankings.StratumCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_stratum_count(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_a
-- Field: TreatmentRankings.StrataWonByA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_summaries_stratum_winner(stratum_summary_id) = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_b
-- Field: TreatmentRankings.StrataWonByB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_summaries_stratum_winner(stratum_summary_id) = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_per_stratum_winner
-- Field: TreatmentRankings.PerStratumWinner
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_treatment_rankings_per_stratum_winner(p_treatment_ranking_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id) = calc_treatment_rankings_stratum_count(p_treatment_ranking_id) THEN ((SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE (CASE WHEN calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id) = calc_treatment_rankings_stratum_count(p_treatment_ranking_id) THEN ((SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE ('none')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_reversal
-- Field: TreatmentRankings.IsReversal
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_reversal(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN calc_treatment_rankings_is_sign_flip(p_treatment_ranking_id) IS NULL THEN ('')::text ELSE (calc_treatment_rankings_is_sign_flip(p_treatment_ranking_id))::text END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_confounders_in_study
-- Field: TreatmentRankings.ConfoundersInStudy
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_confounders_in_study(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_variables WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_variables_is_confounder(stratum_variable_id) = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_paradox_explained
-- Field: TreatmentRankings.IsParadoxExplained
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_paradox_explained(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_treatment_rankings_is_reversal(p_treatment_ranking_id) AND (calc_treatment_rankings_confounders_in_study(p_treatment_ranking_id))::NUMERIC > 0));
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_gap
-- Field: TreatmentRankings.PooledGap
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_gap(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) IS NULL THEN ('')::text ELSE (ABS((COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::numeric ELSE NULL END, 0))))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_loser
-- Field: TreatmentRankings.StrataWonByLoser
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_treatment_rankings_pooled_winner(p_treatment_ranking_id) = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) THEN (calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id))::text ELSE (calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id))::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_paradox_strength
-- Field: TreatmentRankings.ParadoxStrength
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_paradox_strength(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::NUMERIC = 0 THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_pooled_gap(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_gap(p_treatment_ranking_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((COALESCE(CASE WHEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::numeric ELSE NULL END, 0), 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::numeric ELSE NULL END, 0), 0)))::numeric ELSE NULL END, 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_from_weights_a
-- Field: TreatmentRankings.PooledRateFromWeightsA
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_from_weights_a(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_stratum_summaries_weighted_stratum_rate(stratum_summary_id))::numeric), 0) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_from_weights_b
-- Field: TreatmentRankings.PooledRateFromWeightsB
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_from_weights_b(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_stratum_summaries_weighted_stratum_rate(stratum_summary_id))::numeric), 0) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_reversal_intensity
-- Field: TreatmentRankings.ReversalIntensity
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_reversal_intensity(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::NUMERIC = 0 THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_threshold_margin
-- Field: TreatmentRankings.ThresholdMargin
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_threshold_margin(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_treatment_rankings_stratum_count(p_treatment_ranking_id))::NUMERIC = 0 THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_reversal_intensity(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_reversal_intensity(p_treatment_ranking_id))::numeric ELSE NULL END, 0) - COALESCE(0.5, 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_signed_pooled_gap
-- Field: TreatmentRankings.SignedPooledGap
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_signed_pooled_gap(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) IS NULL THEN ('')::text ELSE ((COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id))::numeric ELSE NULL END, 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_weighted_stratum_gap_sum
-- Field: TreatmentRankings.WeightedStratumGapSum
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_weighted_stratum_gap_sum(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_stratum_summaries_weighted_stratum_gap(stratum_summary_id))::numeric), 0) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_sign_flip
-- Field: TreatmentRankings.IsSignFlip
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_sign_flip(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN calc_treatment_rankings_weighted_stratum_gap_sum(p_treatment_ranking_id) IS NULL THEN ('')::text ELSE (CASE WHEN (calc_treatment_rankings_weighted_stratum_gap_sum(p_treatment_ranking_id))::NUMERIC > 0 THEN ((calc_treatment_rankings_signed_pooled_gap(p_treatment_ranking_id))::NUMERIC < 0)::text ELSE ((calc_treatment_rankings_signed_pooled_gap(p_treatment_ranking_id))::NUMERIC > 0)::text END)::text END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_allocation_distortion
-- Field: TreatmentRankings.AllocationDistortion
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_allocation_distortion(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
